// // This module implements a 2-to-1 multiplexer with an enable signal. When enable is high, the output should be equal to input b; when enable is low, the output should be equal to input a.
module mux_2to1_enable (
  input a,
  input b,
  input enable,
  output reg mux_out
);

  always @ (a, b, enable) begin
    if (enable) begin
      mux_out = a;
    end else begin
      mux_out = b;
    end
  end

endmodule
